func dispatchWppp_ppp(slot uint32, recv unsafe.Pointer, w0 unsafe.Pointer, w1 unsafe.Pointer, w2 unsafe.Pointer) (unsafe.Pointer, unsafe.Pointer, unsafe.Pointer) {
	var pw [3]unsafe.Pointer
	var sw [0]uint64
	var fw [0]float64
	pw[0] = w0
	pw[1] = w1
	pw[2] = w2
	var rpw [3]unsafe.Pointer
	var rsw [0]uint64
	var rfw [0]float64
	if core := slotPoolWppp_ppp[slot]; core != nil {
		core(recv, pw[:], sw[:], fw[:], rpw[:], rsw[:], rfw[:])
	}
	return rpw[0], rpw[1], rpw[2]
}

